{
  "executive_summary": "Zero-downtime migration of the Order Management domain from MongoDB to PostgreSQL using a phased Strangler Fig approach with dual-write, shadow-read verification, and incremental cutover. The architecture introduces a Data Access Abstraction Layer (DAAL) to decouple application code from storage, a Change Data Capture (CDC) pipeline for historical backfill, and a dual-write coordinator for real-time synchronization. At 200 writes/min, the system can safely sustain dual-write overhead (~2x write latency) during the transition window without material user impact.",

  "architecture": {
    "components": [
      {
        "name": "Data Access Abstraction Layer (DAAL)",
        "responsibility": "Unified repository interface that routes reads/writes to MongoDB, PostgreSQL, or both depending on migration phase. Encapsulates all storage access behind domain-oriented interfaces (OrderRepository, PaymentRepository). Phase configuration is controlled via feature flags.",
        "boundaries": "Sits between application/domain layer and storage. No domain logic leaks in. No storage-specific types leak out. All data mapping happens here."
      },
      {
        "name": "Dual-Write Coordinator",
        "responsibility": "During Phase 2, ensures every write lands in both MongoDB (primary) and PostgreSQL (secondary) within a single logical operation. MongoDB remains the source of truth; PostgreSQL writes are best-effort with async retry. Logs all discrepancies to a reconciliation table.",
        "boundaries": "Owned by the DAAL. Invisible to the domain layer. Only active during the dual-write migration phase."
      },
      {
        "name": "CDC Backfill Pipeline",
        "responsibility": "Reads the full 8M historical order documents from MongoDB using a cursor-based iterator, transforms them to the relational schema, and bulk-inserts into PostgreSQL. Uses a high-water mark (lastModified timestamp) so it can resume after failure. Runs as a background job with throttling to avoid impacting production reads.",
        "boundaries": "Standalone job. Reads from MongoDB replica secondary. Writes to PostgreSQL. Publishes progress metrics. Does not interact with application traffic."
      },
      {
        "name": "Shadow Read Verifier",
        "responsibility": "During Phase 3, every read hits both stores. The MongoDB result is returned to the caller; the PostgreSQL result is compared asynchronously. Mismatches are logged with full context (order ID, field diffs, timestamps) to a verification dashboard. This builds confidence before cutover.",
        "boundaries": "Runs as an async side-effect within the DAAL read path. Never blocks the primary read. Never affects user-facing responses."
      },
      {
        "name": "Reconciliation Service",
        "responsibility": "Periodically scans the discrepancy log and reconciliation table. Categorizes mismatches (stale data, transformation bug, race condition). Provides dashboard metrics: total verified, match rate, mismatch categories. Blocks cutover if match rate < 99.99%.",
        "boundaries": "Reads from reconciliation table and both databases. Has no write access to production order data."
      },
      {
        "name": "PostgreSQL Schema (Order Management)",
        "responsibility": "Normalized relational schema: orders, order_line_items, payments, payment_events, order_status_history. Foreign keys enforce referential integrity. Indexes optimized for the reporting join queries that motivated this migration.",
        "boundaries": "Owned entirely by the Order Management bounded context. No other service accesses these tables directly—only through the Order Management service APIs."
      },
      {
        "name": "Migration Phase Controller",
        "responsibility": "Feature flag + configuration service that governs the current migration phase (1-5). Supports per-tenant or percentage-based rollout for gradual cutover. Provides instant rollback by flipping the phase back.",
        "boundaries": "Read by the DAAL at runtime. Written by operators via admin API or feature flag system."
      }
    ],
    "interfaces": [
      {
        "from": "Order Management Service (Domain Layer)",
        "to": "Data Access Abstraction Layer",
        "contract": "OrderRepository interface: findById(id), save(order), findByCustomer(customerId, pagination), findForReport(criteria). Returns domain objects, never storage-specific types.",
        "coupling_type": "loose — interface-based, swappable implementation"
      },
      {
        "from": "Data Access Abstraction Layer",
        "to": "Dual-Write Coordinator",
        "contract": "write(mongoOp, pgOp) → Result. Coordinator executes mongoOp first (sync), then pgOp (sync with async retry on failure). Returns success if mongoOp succeeds.",
        "coupling_type": "tight — internal collaboration, same deployment unit"
      },
      {
        "from": "Data Access Abstraction Layer",
        "to": "Shadow Read Verifier",
        "contract": "verify(mongoResult, pgResult, entityId) → fires async comparison. No return value needed on the hot path.",
        "coupling_type": "loose — fire-and-forget async"
      },
      {
        "from": "CDC Backfill Pipeline",
        "to": "MongoDB (Replica Secondary)",
        "contract": "Cursor-based read with lastModified > highWaterMark, batch size 1000, read preference secondaryPreferred.",
        "coupling_type": "data — read-only access to replica"
      },
      {
        "from": "CDC Backfill Pipeline",
        "to": "PostgreSQL",
        "contract": "Bulk INSERT with ON CONFLICT (order_id) DO UPDATE for idempotency. Batch size 500 rows per transaction.",
        "coupling_type": "data — write access to target schema"
      },
      {
        "from": "Reconciliation Service",
        "to": "Migration Phase Controller",
        "contract": "Reports match_rate metric. Phase Controller will not allow advancement to Phase 4 (cutover) unless match_rate >= 99.99% sustained for 24 hours.",
        "coupling_type": "loose — metric-based gate"
      }
    ],
    "data_flow": "Phase 1 (Prepare): Deploy PostgreSQL schema and DAAL with MongoDB-only routing. No behavior change. Phase 2 (Backfill + Dual-Write): Start CDC backfill of 8M historical docs. Simultaneously enable dual-write for all new writes. MongoDB is primary for reads. Backfill catches up in ~6-10 hours at throttled rate. Phase 3 (Shadow Reads): Enable shadow-read verification. Every read returns MongoDB data but async-compares with PostgreSQL. Reconciliation dashboard tracks match rate. Phase 4 (Cutover): Flip primary to PostgreSQL for reads. MongoDB becomes secondary write (for rollback safety). Monitor for 48-72 hours. Phase 5 (Decommission): Stop writes to MongoDB. Archive MongoDB data. Remove DAAL routing logic, leaving clean PostgreSQL implementation.",
    "patterns_used": [
      {
        "pattern": "Strangler Fig Migration",
        "rationale": "Incrementally shifts traffic from old to new store without big-bang cutover. Each phase is independently reversible. This is the industry-standard pattern for zero-downtime database migrations."
      },
      {
        "pattern": "Dual-Write with Primary/Secondary",
        "rationale": "MongoDB stays the source of truth during migration, so any PostgreSQL write failure is non-fatal. Avoids distributed transaction complexity (no 2PC needed). Discrepancies are caught by reconciliation."
      },
      {
        "pattern": "Shadow Reads (Dark Launch)",
        "rationale": "Builds empirical confidence that PostgreSQL returns identical results before cutover. Catches schema mapping bugs, data transformation issues, and edge cases that unit tests miss."
      },
      {
        "pattern": "Repository Pattern (Data Access Abstraction)",
        "rationale": "Decouples the domain layer from storage concerns entirely. The migration becomes invisible to business logic. After migration, the abstraction can be simplified to direct PostgreSQL access."
      },
      {
        "pattern": "Idempotent Backfill with High-Water Mark",
        "rationale": "At 8M documents, the backfill will take hours. It must be resumable after crashes. Using lastModified as a cursor with ON CONFLICT upserts ensures idempotency and crash-safety."
      },
      {
        "pattern": "Feature Flag Phased Rollout",
        "rationale": "Allows percentage-based cutover (e.g., 1% → 10% → 50% → 100% of reads from PostgreSQL). Instant rollback by flipping the flag. Reduces blast radius of any issue."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: orderId, contains: lineItems[], statusHistory[], shippingAddress)",
          "Payment (root: paymentId, contains: paymentEvents[], linked to orderId via FK)"
        ]
      },
      {
        "name": "Migration Infrastructure",
        "classification": "generic",
        "aggregates": [
          "MigrationPhase (current phase, rollout percentage, gate conditions)",
          "ReconciliationRecord (entityId, source, target, mismatchFields, resolvedAt)"
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Migration Infrastructure",
        "relationship": "Conformist — Migration infrastructure conforms to the Order domain model. It never dictates schema changes to the domain."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Dual-write with MongoDB as primary (no distributed transactions)",
      "gains": "Zero risk to production during migration. PostgreSQL failures are non-fatal. No 2PC complexity. Simple rollback — just stop writing to PostgreSQL.",
      "sacrifices": "Temporary inconsistency window between stores (writes land in MongoDB first, then PostgreSQL). If PostgreSQL write fails and retry queue backs up, reconciliation must catch it.",
      "alternatives_considered": [
        "Two-Phase Commit (2PC): Guarantees atomicity across both stores but adds significant latency, operational complexity, and a new failure mode. Rejected — overkill for a temporary migration state.",
        "Change Data Capture only (no dual-write): Use MongoDB change streams to replicate to PostgreSQL. Simpler but introduces replication lag that makes shadow-read verification unreliable. Harder to reason about ordering guarantees.",
        "Big-bang migration with maintenance window: Simplest but violates zero-downtime constraint."
      ]
    },
    {
      "decision": "Normalized relational schema in PostgreSQL (not document-mirroring JSONB)",
      "gains": "Fulfills the stated goals: ACID transactions across order+payment, efficient join queries for reporting, foreign key constraints preventing orphans. This is why we're migrating.",
      "sacrifices": "Schema transformation adds complexity to the backfill pipeline. Document-to-relational mapping must handle embedded arrays (lineItems), nested objects, and any schema inconsistencies in existing MongoDB documents.",
      "alternatives_considered": [
        "JSONB columns mirroring MongoDB documents: Faster migration but defeats the purpose. You'd still lack FK constraints and efficient joins.",
        "Hybrid: Normalized core fields + JSONB for flexible/optional fields: Reasonable compromise if some order fields are highly variable. Could be adopted for metadata-like fields."
      ]
    },
    {
      "decision": "Shadow reads before cutover (Phase 3)",
      "gains": "Empirical proof that PostgreSQL returns correct data. Catches edge cases: timezone handling, decimal precision, null vs missing fields, Unicode normalization, array ordering.",
      "sacrifices": "Doubles read load during verification phase. At 200 writes/min, read traffic is likely higher (assume 5-10x). Both databases must handle the full read load simultaneously.",
      "alternatives_considered": [
        "Sample-based verification: Only shadow-read 1-5% of traffic. Lower load but lower confidence. Acceptable if read traffic is very high — can start with sampling and increase.",
        "Batch comparison job: Periodically dump and diff both stores. Catches drift but misses transient issues and doesn't test the actual read path."
      ]
    },
    {
      "decision": "Single-service migration (not microservice extraction)",
      "gains": "Keeps the migration scope minimal. We're changing the storage layer, not the service topology. Avoids the combinatorial complexity of simultaneously migrating storage AND extracting a service.",
      "sacrifices": "If the team later wants to extract Order Management into its own microservice, that's a separate effort. But it's easier to do after the PostgreSQL migration since the DAAL already provides a clean interface.",
      "alternatives_considered": [
        "Simultaneous service extraction + DB migration: Higher risk, longer timeline, more moving parts. Classic mistake — change one thing at a time."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Migration Phase Controller (Feature Flags)",
      "evolution_path": "Can support per-tenant rollout, percentage-based cutover, or even per-entity-type phasing (e.g., migrate orders first, payments second). After migration completes, the flag infrastructure can be removed or repurposed."
    },
    {
      "area": "Data Access Abstraction Layer",
      "evolution_path": "Post-migration, the DAAL can be simplified to a direct PostgreSQL repository. Or it can be retained if further storage changes are anticipated (e.g., read replicas, caching layer). The interface contract with the domain layer is the lasting value."
    },
    {
      "area": "PostgreSQL Schema",
      "evolution_path": "Once on PostgreSQL, adding materialized views for reporting, partitioning orders by date for archival, or adding full-text search indexes becomes straightforward. The relational foundation supports these evolutions cleanly."
    },
    {
      "area": "Reconciliation Service",
      "evolution_path": "Can be generalized into a reusable migration toolkit for future MongoDB→PostgreSQL migrations of other domains. The pattern (dual-write, shadow-read, reconcile, cutover) is repeatable."
    }
  ],

  "rigidity_points": [
    {
      "area": "Document-to-Relational Schema Mapping",
      "reason": "The transformation logic from MongoDB documents to normalized PostgreSQL rows must be precisely defined and frozen before backfill begins. Any schema mapping changes require re-running or patching the backfill. This mapping is the most error-prone part of the migration and must be thoroughly tested before Phase 2."
    },
    {
      "area": "Order Aggregate Consistency Boundary",
      "reason": "In PostgreSQL, the Order aggregate (order + line items + status history) must be written in a single transaction. This is a desired rigidity — it's the whole reason for migrating. But it means the aggregate boundary must be correctly defined upfront. Getting this wrong means either too-large transactions (performance) or too-small transactions (broken invariants)."
    },
    {
      "area": "MongoDB Document Schema Assumptions",
      "reason": "The backfill pipeline assumes a known document structure. MongoDB's schemaless nature means 8M documents may have evolved over time (added fields, changed types, missing fields). A pre-migration schema analysis scan is mandatory to discover variants before building the transformation."
    }
  ],

  "risks": [
    {
      "risk": "MongoDB document schema inconsistencies across 8M records — fields missing, type mismatches, embedded vs referenced subdocuments varying by age of record",
      "severity": "critical",
      "mitigation": "Run a schema analysis job FIRST (e.g., variety.js or a custom aggregation pipeline) to catalog all document shapes and field types. Build transformation logic that handles every variant. Write defensive mapping code with explicit error handling and a dead-letter queue for unmappable documents."
    },
    {
      "risk": "Dual-write PostgreSQL failures accumulate faster than retry can process, causing growing inconsistency",
      "severity": "high",
      "mitigation": "Implement a persistent retry queue (not in-memory) with exponential backoff. Monitor queue depth with alerting. If queue exceeds threshold, the Reconciliation Service flags it and blocks Phase 4 advancement. Worst case: re-run targeted backfill for the affected time window."
    },
    {
      "risk": "Shadow read comparison shows false mismatches due to eventual consistency timing (write hits MongoDB, shadow-read hits PostgreSQL before dual-write completes)",
      "severity": "medium",
      "mitigation": "Shadow read comparisons should tolerate a configurable staleness window (e.g., ignore mismatches for records modified in last 5 seconds). Log these as 'timing-expected' separately from true mismatches."
    },
    {
      "risk": "Backfill pipeline impacts production MongoDB read performance",
      "severity": "medium",
      "mitigation": "Read from a secondary replica, not the primary. Throttle batch reads with configurable delay between batches. Monitor replica lag — pause backfill if lag exceeds threshold. At 8M docs with batch size 1000 and 100ms delay between batches, backfill completes in ~13 minutes of pure read time, but throttled to hours for safety."
    },
    {
      "risk": "PostgreSQL write latency under dual-write doubles the p99 for order creation, impacting user experience",
      "severity": "medium",
      "mitigation": "Make PostgreSQL writes async (fire-and-forget with retry queue) rather than synchronous. MongoDB write returns success to the user immediately. PostgreSQL write is best-effort. At 200 writes/min (~3.3/sec), PostgreSQL can handle this trivially even if writes take 50ms each."
    },
    {
      "risk": "Rollback after Phase 4 cutover loses writes that only went to PostgreSQL",
      "severity": "high",
      "mitigation": "During Phase 4, maintain reverse dual-write: PostgreSQL is primary, MongoDB is secondary. This ensures MongoDB stays current for 48-72 hours post-cutover. Only stop MongoDB writes (Phase 5) after sustained stability confirmation."
    },
    {
      "risk": "Array ordering differences between MongoDB and PostgreSQL (e.g., line items order) cause false shadow-read mismatches",
      "severity": "low",
      "mitigation": "Shadow read comparisons should use order-independent comparison for arrays (compare as sets) or enforce explicit ordering via a sequence/position column in PostgreSQL."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Execute in 5 phases over 4-6 weeks. Phase 1 (Week 1): Deploy PostgreSQL schema, DAAL with MongoDB-only routing, and schema analysis job. Phase 2 (Week 2): Enable dual-write and start backfill. Phase 3 (Week 2-3): Enable shadow reads, monitor reconciliation dashboard, fix transformation bugs. Phase 4 (Week 3-4): Gradual cutover — 1% → 10% → 50% → 100% reads from PostgreSQL. Reverse dual-write to keep MongoDB current. Phase 5 (Week 5-6): After 2 weeks of stable operation, decommission MongoDB writes and archive data.",
    "files_to_create_or_modify": [
      "src/order-management/repositories/OrderRepository.ts — Abstract interface (if not already present)",
      "src/order-management/repositories/MongoOrderRepository.ts — Existing implementation, to be wrapped by DAAL",
      "src/order-management/repositories/PostgresOrderRepository.ts — New implementation against relational schema",
      "src/order-management/repositories/DualWriteOrderRepository.ts — DAAL: routes reads/writes based on migration phase",
      "src/order-management/migration/BackfillPipeline.ts — CDC backfill job: MongoDB cursor → transform → PostgreSQL bulk insert",
      "src/order-management/migration/ShadowReadVerifier.ts — Async comparison of MongoDB vs PostgreSQL read results",
      "src/order-management/migration/ReconciliationService.ts — Mismatch tracking, categorization, and dashboard metrics",
      "src/order-management/migration/SchemaAnalyzer.ts — Pre-migration MongoDB document shape analysis",
      "src/order-management/migration/DocumentTransformer.ts — MongoDB document → PostgreSQL row mapping with variant handling",
      "db/migrations/001_create_orders_schema.sql — PostgreSQL DDL: orders, line_items, payments, payment_events, status_history tables",
      "db/migrations/002_create_reconciliation_tables.sql — Reconciliation and retry queue tables",
      "config/migration-phases.json — Feature flag configuration for migration phase control"
    ],
    "patterns_to_follow": "Repository Pattern for all data access. Strategy Pattern within the DAAL to swap between MongoDB-only, dual-write, and PostgreSQL-only modes. Builder Pattern for the DocumentTransformer to handle MongoDB document variants. Circuit Breaker on PostgreSQL writes during dual-write phase — if PostgreSQL is unhealthy, stop dual-writes temporarily rather than filling the retry queue.",
    "pitfalls_to_avoid": [
      "DO NOT attempt a big-bang migration or any approach requiring downtime — the constraint is absolute",
      "DO NOT use distributed transactions (2PC/XA) between MongoDB and PostgreSQL — the operational complexity is not worth it for a temporary migration state",
      "DO NOT assume MongoDB documents have a consistent schema — run the schema analysis FIRST",
      "DO NOT make PostgreSQL writes synchronous in the hot path — use async with retry to avoid impacting user-facing latency",
      "DO NOT skip the shadow-read verification phase — this is where you catch the bugs that will embarrass you in production",
      "DO NOT cutover reads before the reconciliation match rate hits 99.99% sustained for 24 hours — premature cutover is the #1 cause of failed migrations",
      "DO NOT decommission MongoDB until PostgreSQL has been the sole primary for at least 2 weeks with reverse dual-write keeping MongoDB current",
      "DO NOT change the relational schema during the backfill — freeze the schema before Phase 2 begins",
      "DO NOT run the backfill against the MongoDB primary — always use a secondary replica with read preference secondaryPreferred"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "Strangler Fig with dual-write is the correct migration pattern for this scenario — well-established, battle-tested",
      "Phase ordering (prepare → backfill+dual-write → shadow-read → cutover → decommission) is sound",
      "Risk identification around schema inconsistency and timing issues",
      "PostgreSQL schema design direction (normalized, FK-enforced) aligns with stated migration goals"
    ],
    "low_confidence_areas": [
      "Exact PostgreSQL schema design — depends on current MongoDB document structure which has not been analyzed",
      "Retry queue sizing and backpressure thresholds — need production latency data for PostgreSQL writes",
      "Shadow read comparison logic — edge cases depend on actual data types and field semantics (e.g., how are monetary values stored? Decimal precision?)",
      "Timeline estimate (4-6 weeks) — depends heavily on MongoDB schema consistency and team familiarity with PostgreSQL"
    ],
    "assumptions": [
      "MongoDB documents for orders have a reasonably consistent schema (variations exist but are manageable, not chaotic)",
      "200 writes/min is sustained average, not burst peak — if peak is significantly higher, async write queue needs more careful sizing",
      "The application layer already has some form of repository or data access pattern — if data access is scattered throughout the codebase, Phase 1 scope increases significantly",
      "PostgreSQL instance is already provisioned or can be provisioned without organizational blockers",
      "The team has operational experience with PostgreSQL or can acquire it — running both databases simultaneously increases operational surface area"
    ]
  }
}

